{% if product %}
  <button id="shareButton" class="share-icon-button m-tooltip m-tooltip--bottom" aria-label="Share this product">
<svg class="share-icon m-svg-icon--medium"
     fill="currentColor"
     stroke="currentColor"
     stroke-width="0.1"
     xmlns="http://www.w3.org/2000/svg"
     viewBox="0 0 32 32">

  <path d="m20.08936 29a3.02941 3.02941 0 0 1 -2.72022-1.68555l-4.07178-8.14306a1.04592 1.04592 0 0 0 -.46777-.46826l-8.144-4.07227a3.0485 3.0485 0 0 1 .50293-5.65137l19.90039-5.853a3.04848 3.04848 0 0 1 3.78467 3.78467l-5.853 19.90039a3.03237 3.03237 0 0 1 -2.6543 2.17627c-.09284.00779-.18513.01218-.27692.01218zm5.87255-24.001a1.08177 1.08177 0 0 0 -.30859.04639l-19.90039 5.853a1.04816 1.04816 0 0 0 -.17285 1.94336l8.14306 4.07177a3.06409 3.06409 0 0 1 1.36377 1.36426l4.07129 8.14209a1.04816 1.04816 0 0 0 1.94336-.17285l5.853-19.90039a1.02671 1.02671 0 0 0 -.26416-1.03711 1.0455 1.0455 0 0 0 -.72849-.31052z"/>

  <path d="m14.08008 19.54a1 1 0 0 1 -.687-1.72656l6.91992-6.54a.99994.99994 0 1 1 1.374 1.45312l-6.91992 6.54a.99546.99546 0 0 1 -.687.27344z"/>

</svg>
<span class="m-tooltip__content m-wishlist-button-text" data-atc-text="" data-revert-text="Remove from wishlist">Share</span>
  </button>

  <style>
    .share-icon-button {
transition: all var(--m-duration-default, .25s) ease;
    border: 1px solid rgb(var(--color-border));
    padding: 11px;
      cursor: pointer;
display: flex;
    justify-content: flex-end;
    position: absolute;
    top: 0px;
    right: 0;
    }

@media (max-width: 768px) {
      .share-icon-button {
        margin-top: -10px;
      }
    }

    .share-icon {
      width: 21px;
      height: 21px;
      color: #000;
    }
.share-icon-button:hover {
        box-shadow: 0 0 0 .2rem rgb(var(--color-button-hover));
border: 1px solid rgb(var(--color-button-hover));
    }
    .share-icon-button:hover{
      background: rgb(var(--color-button-hover));
        color: rgb(var(--color-button-text-hover));
    }
  </style>

  <script>
    document.addEventListener("DOMContentLoaded", function () {
      const shareButton = document.getElementById("shareButton");

      shareButton.addEventListener("click", async () => {
        if (navigator.share) {
          try {
            await navigator.share({
              title: "{{ product.title | escape }}",
              url: "{{ shop.url }}{{ product.url }}"
            });
            console.log('Product shared successfully');
          } catch (err) {
            console.error('Error sharing the product:', err);
          }
        } else {
          alert("Web Share API is not supported in your browser.");
        }
      });
    });
  </script>
{% endif %}
